// ─────────────────────────────────────────────────────────
// NODO 1 — Legge il file JSON da Google Drive e lo appiattisce
// in righe { ts, sn, energy_kwh, power_w } pronte per Sheets.
//
// Il file Drive è un array di payload, uno per ogni
// invio del sensore. Ogni payload ha la struttura:
// { hn, items: [{ li, sn, ms: [{ iName, ts, un, va }] }] }
// ─────────────────────────────────────────────────────────

const item = $input.first();

// Leggi il binario scaricato da Google Drive
let text;
try {
  const buffer = await this.helpers.getBinaryDataBuffer(item, 'data');
  text = buffer.toString('utf8');
} catch (e) {
  throw new Error('Errore lettura file Drive: ' + e.message);
}

let rawData;
try {
  rawData = JSON.parse(text);
} catch (e) {
  throw new Error('JSON non valido nel file sensori: ' + e.message);
}

if (!Array.isArray(rawData)) rawData = [rawData];

// Campo energia per tipo di sensore (contatori cumulativi kWh)
const ENERGY_FIELD = {
  TOTAL_POWER:   'Energia_Attiva_Positiva',
  CANTEEN_POWER: 'Energia_Attiva_Positiva',
  FV_POWER:      'Energia trifase att Positiva',
  HEAT_POWER:    'Energia trifase att Positiva',
  CAR_CHARGER:   'Energia trifase att Positiva'
};

// Campo potenza istantanea (W)
const POWER_FIELD = {
  TOTAL_POWER:   'Potenza_attiva_trifase',
  CANTEEN_POWER: 'Potenza_attiva_trifase',
  FV_POWER:      'Potenza attiva trifase',
  HEAT_POWER:    'Potenza attiva trifase',
  CAR_CHARGER:   'Potenza attiva trifase'
};

const records = [];

for (const payload of rawData) {
  if (!payload || !payload.items) continue;
  for (const device of payload.items) {
    const sn = device.sn;
    if (!ENERGY_FIELD[sn]) continue; // ignora sensori non mappati
    const ms = device.ms || [];
    const energyMs = ms.find(m => m.iName === ENERGY_FIELD[sn]);
    const powerMs  = ms.find(m => m.iName === POWER_FIELD[sn]);
    const ts = (energyMs || ms[0] || {}).ts || new Date().toISOString();
    if (energyMs) {
      records.push({
        ts,
        sn,
        energy_kwh: parseFloat(energyMs.va || 0),
        power_w:    parseFloat(powerMs?.va || 0)
      });
    }
  }
}

if (records.length === 0) {
  throw new Error('Nessun record valido trovato — controlla il formato del file sensori.');
}

return records.map(r => ({ json: r }));

// ─────────────────────────────────────────────────────────
// NODO 2 — Legge tutti i readings dal foglio Google Sheets
// e produce 3 item (24h.json, 7d.json, 30d.json) già
// in formato base64, pronti per essere pushati su GitHub.
//
// Logica delta: i contatori sono cumulativi (kWh),
// quindi consumo = E(t_fine) - E(t_inizio).
// ─────────────────────────────────────────────────────────

const allItems = $input.all();

// Costruisci dataset ordinato per timestamp
const readings = allItems
  .map(i => ({
    ts:         new Date(i.json.ts),
    sn:         String(i.json.sn),
    energy_kwh: parseFloat(i.json.energy_kwh || 0),
    power_w:    parseFloat(i.json.power_w || 0)
  }))
  .filter(r => !isNaN(r.ts.getTime()) && r.energy_kwh >= 0)
  .sort((a, b) => a.ts - b.ts);

if (readings.length === 0) {
  throw new Error('Nessun reading valido in Google Sheets. Esegui prima almeno un ciclo di raccolta dati.');
}

const now = new Date();

// Ultima lettura disponibile <= beforeTs per un dato sensore
function latestBefore(sn, beforeTs) {
  const recs = readings.filter(r => r.sn === sn && r.ts <= beforeTs);
  return recs.length ? recs[recs.length - 1] : null;
}

// Delta kWh tra due istanti (0 se dati insufficienti)
function deltaKwh(sn, fromTs, toTs) {
  const start = latestBefore(sn, fromTs);
  const end   = latestBefore(sn, toTs);
  if (!start || !end || end.energy_kwh < start.energy_kwh) return 0;
  return Math.round(end.energy_kwh - start.energy_kwh);
}

// ════════════════════════════════════════
// 24H — fasce da 4 ore
// ════════════════════════════════════════
const h24ago = new Date(now.getTime() - 24 * 3600 * 1000);
const slots24 = [];
for (let h = 0; h < 24; h += 4) {
  const s = new Date(h24ago.getTime() + h * 3600 * 1000);
  const e = new Date(s.getTime() + 4 * 3600 * 1000);
  slots24.push({ label: String(s.getHours()).padStart(2, '0'), s, e });
}

const d24 = {
  updated_at: now.toISOString().slice(0, 16).replace('T', ' '),
  totale_vs_fv: {
    consumo:      deltaKwh('TOTAL_POWER', h24ago, now),
    fotovoltaico: deltaKwh('FV_POWER',    h24ago, now)
  },
  consumo_totale: slots24.map(sl => ({
    label: sl.label,
    value: deltaKwh('TOTAL_POWER', sl.s, sl.e)
  })),
  consumo_parziale: {
    labels: slots24.map(sl => sl.label),
    series: {
      'Gruppo Frigo':   slots24.map(sl => deltaKwh('HEAT_POWER',    sl.s, sl.e)),
      'Mensa':          slots24.map(sl => deltaKwh('CANTEEN_POWER', sl.s, sl.e)),
      'Colonnina Auto': slots24.map(sl => deltaKwh('CAR_CHARGER',   sl.s, sl.e))
    }
  }
};

// ════════════════════════════════════════
// 7D — un punto per ogni giorno
// ════════════════════════════════════════
const d7ago = new Date(now.getTime() - 7 * 24 * 3600 * 1000);
const DAY_IT = ['Dom', 'Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab'];
const days7 = [];
for (let d = 6; d >= 0; d--) {
  const dayStart = new Date(now);
  dayStart.setHours(0, 0, 0, 0);
  dayStart.setDate(dayStart.getDate() - d);
  const dayEnd = new Date(dayStart.getTime() + 24 * 3600 * 1000);
  days7.push({ label: DAY_IT[dayStart.getDay()], s: dayStart, e: dayEnd });
}

const d7 = {
  updated_at: now.toISOString().slice(0, 16).replace('T', ' '),
  totale_vs_fv: {
    consumo:      deltaKwh('TOTAL_POWER', d7ago, now),
    fotovoltaico: deltaKwh('FV_POWER',    d7ago, now)
  },
  consumo_totale: days7.map(sl => ({
    label: sl.label,
    value: deltaKwh('TOTAL_POWER', sl.s, sl.e)
  })),
  consumo_parziale: {
    labels: days7.map(sl => sl.label),
    series: {
      'Gruppo Frigo':   days7.map(sl => deltaKwh('HEAT_POWER',    sl.s, sl.e)),
      'Mensa':          days7.map(sl => deltaKwh('CANTEEN_POWER', sl.s, sl.e)),
      'Colonnina Auto': days7.map(sl => deltaKwh('CAR_CHARGER',   sl.s, sl.e))
    }
  }
};

// ════════════════════════════════════════
// 30D — un punto per ogni settimana
// ════════════════════════════════════════
const d30ago = new Date(now.getTime() - 30 * 24 * 3600 * 1000);
const weeks = [];
for (let w = 0; w < 4; w++) {
  const wStart = new Date(d30ago.getTime() + w * 7 * 24 * 3600 * 1000);
  const wEnd   = new Date(wStart.getTime() + 7 * 24 * 3600 * 1000);
  weeks.push({ label: `W${w + 1}`, s: wStart, e: wEnd });
}

const d30 = {
  updated_at: now.toISOString().slice(0, 16).replace('T', ' '),
  totale_vs_fv: {
    consumo:      deltaKwh('TOTAL_POWER', d30ago, now),
    fotovoltaico: deltaKwh('FV_POWER',    d30ago, now)
  },
  consumo_totale: weeks.map(sl => ({
    label: sl.label,
    value: deltaKwh('TOTAL_POWER', sl.s, sl.e)
  })),
  consumo_parziale: {
    labels: weeks.map(sl => sl.label),
    series: {
      'Gruppo Frigo':   weeks.map(sl => deltaKwh('HEAT_POWER',    sl.s, sl.e)),
      'Mensa':          weeks.map(sl => deltaKwh('CANTEEN_POWER', sl.s, sl.e)),
      'Colonnina Auto': weeks.map(sl => deltaKwh('CAR_CHARGER',   sl.s, sl.e))
    }
  }
};

// Output: 3 item, uno per ogni file da aggiornare su GitHub
const b64 = obj => Buffer.from(JSON.stringify(obj, null, 2)).toString('base64');
return [
  { json: { filename: 'data/24h.json', base64Content: b64(d24) } },
  { json: { filename: 'data/7d.json',  base64Content: b64(d7)  } },
  { json: { filename: 'data/30d.json', base64Content: b64(d30) } }
];

